function TaskDialog()
this:AddTalk("你好。")
this:AddTalk("有什么想去的地方吗？")
this:AddTalk("<p><n color=\"255,0,255,255\">最近开发了新的地图可以自动打怪，挂机必备“专属VIP地图”。</n></p>");
this:AddTalk("<p><n color=\"255,255,255,0\">开放时间：全天，只能1玩家进入！</n></p>");
this:AddTalk("<p><n color=\"255,0,255,0\">只有VIP10玩家才可进入VIP地图哦！</n></p>");
this:AddTaskCmdItem("进入VIP地图【时装布料】", "v5125", 160103, 1)
this:AddTaskCmdItem("进入VIP地图【怪物图鉴】", "v5125", 160103, 2)
this:AddTaskCmdItem("进入VIP地图【传国碎片】", "v5125", 160103, 3)
this:AddTaskCmdItem("进入VIP地图【王者碎片】", "v5125", 160103, 4)
this:AddTaskCmdItem("进入VIP地图【儿女碎片】", "v5125", 160103, 5)
this:AddCloseItem("离开")
end

